update post_media_asset
set lifecycle = 'UPLOADED',
    oss_version_id = #{versionId, jdbcType=BINARY},
    public_url = #{publicUrl},
    update_time = #{updateTime}
where id = #{id, jdbcType=BINARY}

update post_media_asset
set lifecycle = 'DELETED',
    update_time = #{updateTime}
where id = #{id, jdbcType=BINARY}
  and lifecycle = 'DRAFT'

